namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast, Yogurt, Tikka spice mix, Onion, Garlic, Ginger, Tomato sauce, Heavy cream, Cilantro, Rice", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and simmer 15 minutes.\n5. Stir in cream and cooked chicken.\n6. Serve over basmati rice with cilantro.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheddar cheese, Sour cream, Salsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onions, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Stir-fry shrimp until pink, set aside.\n3. Scramble eggs in the wok.\n4. Add drained noodles and sauce mixture.\n5. Toss with shrimp, bean sprouts, and green onions.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract, Powdered sugar", Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs and sugar until thick.\n3. Fold in chocolate mixture and flour.\n4. Pour into greased ramekins.\n5. Bake at 425°F for 12-14 minutes.\n6. Invert onto plates and dust with powdered sugar.", AverageRating = 4.9, RatingCount = 31 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan cheese, Croutons, Caesar dressing, Lemon, Anchovy paste, Garlic", Steps = "1. Tear romaine into bite-sized pieces.\n2. Make dressing: whisk garlic, anchovy paste, lemon juice, and olive oil.\n3. Toss lettuce with dressing.\n4. Add shaved parmesan and croutons.\n5. Serve immediately.", AverageRating = 4.0, RatingCount = 6 },
    };

    private int _nextId = 7;

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
        }
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

