@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/">Browse recipes</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label class="form-label" for="title">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="category">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                        <option value="">Select a category...</option>
                        <option value="Italian">Italian</option>
                        <option value="Indian">Indian</option>
                        <option value="Mexican">Mexican</option>
                        <option value="Thai">Thai</option>
                        <option value="Desserts">Desserts</option>
                        <option value="Salads">Salads</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label" for="ingredients">Ingredients (comma-separated)</label>
                    <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="Submission.Ingredients" placeholder="Flour, Sugar, Butter, Apples..." />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="steps">Steps (one per line)</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Submission.Steps" placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients..." />
                </div>

                <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeSubmission Submission { get; set; } = new();
    private bool SubmitSuccess { get; set; }

    private bool IsValid => !string.IsNullOrWhiteSpace(Submission.Title)
                         && !string.IsNullOrWhiteSpace(Submission.Category)
                         && !string.IsNullOrWhiteSpace(Submission.Ingredients)
                         && !string.IsNullOrWhiteSpace(Submission.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.SubmitRecipe(Submission);
        SubmitSuccess = true;
    }
}

